//! Metadata for route-backed page components.

use super::from_request::{ExtractError, RouteContext};
use reinhardt_core::page::Outlet;

/// Compile-time metadata exposed by props types generated by `#[component]`.
pub trait ComponentInfo {
	/// Returns the client route pattern.
	fn path() -> &'static str;

	/// Returns the route name used for reverse lookup.
	fn name() -> &'static str;

	/// Returns the PascalCase component name used by `page!` brace form.
	fn component_name() -> &'static str;

	/// Returns the snake_case render function name.
	fn function_name() -> &'static str;

	/// Returns the generated props type name.
	fn props_type_name() -> &'static str;
}

/// Compile-time metadata exposed by props types generated by `#[layout]`.
pub trait LayoutInfo {
	/// Returns the client layout route pattern.
	fn path() -> &'static str;

	/// Returns the layout route name used for diagnostics.
	fn name() -> &'static str;

	/// Returns the PascalCase component name used by `page!` brace form.
	fn component_name() -> &'static str;

	/// Returns the snake_case render function name.
	fn function_name() -> &'static str;

	/// Returns the generated props type name.
	fn props_type_name() -> &'static str;
}

/// Builds layout props from route context and router-managed outlet content.
pub trait FromLayoutRequest: Sized {
	/// Construct `Self` from the request context and the matched child outlet.
	///
	/// # Errors
	///
	/// Returns [`ExtractError`] when a required path or query parameter is
	/// missing or fails to parse.
	fn from_layout_request(ctx: &RouteContext, outlet: Outlet) -> Result<Self, ExtractError>;
}

/// Static metadata submitted by `#[component]` for diagnostics and tooling.
pub struct ComponentMetadata {
	/// Client route pattern.
	pub path: &'static str,
	/// Route name used by `ClientRouter`.
	pub name: &'static str,
	/// PascalCase component name.
	pub component_name: &'static str,
	/// Render function name.
	pub function_name: &'static str,
	/// Generated props type name.
	pub props_type_name: &'static str,
	/// Rust module path containing the component declaration.
	pub module_path: &'static str,
}

inventory::collect!(ComponentMetadata);
